/* eslint-disable react/no-unescaped-entities */
import type { ChangeEvent } from 'react';
import React, { memo, useEffect, useMemo, useState } from '@teact';
import { getActions, withGlobal } from '../../../../global';

import type { AddUrgentRuleRequest, UpdateUrgentRuleRequest } from './types';

import { selectTabState } from '../../../../global/selectors';
import { urgentCheckTask } from '../../ai-task/urgent-check-task';
import { loadUrgentRules, useUrgentRules } from '../../hook/use-urgent-rules';
import { addGroupUrgentSettingd, updateGroupUrgentSettingd } from '../../utils/chat-api';

import useLastCallback from '../../../../hooks/useLastCallback';

import Icon from '../../../common/icons/Icon';
import FloatingActionButton from '../../../ui/FloatingActionButton';
import InputText from '../../../ui/InputText';
import Spinner from '../../../ui/Spinner';
import Switcher from '../../../ui/Switcher';
import TextArea from '../../../ui/TextArea';
import { ExclamationCircleIcon } from './ExclamationCircleIcon';

import MessageIconPath from '../../assets/message.png';

const ERROR_RULE_MISSING = 'Please enter an alert rule.';
const ERROR_PHONE_MISSING = 'Please enter a phone number.';

interface OwnProps {
  chatId?: string;
}

interface StateProps {
  currentUserId?: string;
  editingRuleId?: number;
}

export const AddUrgentAlert = ({
  chatId, currentUserId, editingRuleId,
}: OwnProps & StateProps) => {
  const { toggleAddUrgentAlert } = getActions();
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | undefined>();
  const [rule, setRule] = useState<string | undefined>();
  const [notification, setNotification] = useState(false);
  const [callAlert, setCallAlert] = useState(false);
  const [phoneNumber, setPhoneNumber] = useState<string | undefined>();

  // 记录初始值，用于判断是否有变化
  const [initialRule, setInitialRule] = useState<string | undefined>();
  const [initialNotification, setInitialNotification] = useState(false);
  const [initialCallAlert, setInitialCallAlert] = useState(false);
  const [initialPhone, setInitialPhone] = useState<string | undefined>();

  // 编辑模式：通过 hook 加载已有数据预填表单
  const { rules, phone } = useUrgentRules({
    chatId: editingRuleId ? chatId : undefined,
    currentUserId: editingRuleId ? currentUserId : undefined,
  });

  useEffect(() => {
    if (!editingRuleId || !rules.length) return;
    const target = rules.find((r) => r.id === editingRuleId);
    if (!target) return;
    setRule(target.rule);
    setNotification(target.is_vibration);
    setCallAlert(target.is_call);
    setInitialRule(target.rule);
    setInitialNotification(target.is_vibration);
    setInitialCallAlert(target.is_call);
  }, [editingRuleId, rules]);

  useEffect(() => {
    if (phone) {
      setPhoneNumber(phone);
      setInitialPhone(phone);
    }
  }, [phone]);

  const handlePhoneNumberChange = useLastCallback((e: ChangeEvent<HTMLInputElement>) => {
    setPhoneNumber(e.target.value);
  });
  const handleRuleChange = useLastCallback((e: ChangeEvent<HTMLTextAreaElement>) => {
    setRule(e.target.value);
  });
  const handleCallAlertChange = useLastCallback((e: ChangeEvent<HTMLInputElement>) => {
    setCallAlert(e.currentTarget.checked);
  });
  const handleNotificationChange = useLastCallback((e: ChangeEvent<HTMLInputElement>) => {
    setNotification(e.currentTarget.checked);
  });
  const handleSave = useLastCallback(() => {
    if (!rule?.trim().length) {
      setError(ERROR_RULE_MISSING);
      return;
    }
    if (callAlert && !phoneNumber?.trim().length) {
      setError(ERROR_PHONE_MISSING);
      return;
    }
    if (!currentUserId || !chatId) return;

    setIsLoading(true);

    const baseFields = {
      user_id: currentUserId,
      chat_id: chatId,
      rule: rule.trim(),
      is_open: true,
      is_call: callAlert,
      is_vibration: notification,
      phone: phoneNumber?.trim(),
    };

    const request: Promise<any> = editingRuleId
      ? updateGroupUrgentSettingd({ ...baseFields, id: String(editingRuleId) } as UpdateUrgentRuleRequest)
      : addGroupUrgentSettingd(baseFields as AddUrgentRuleRequest);

    request
      .then(() => {
        // 刷新 hook 缓存后同步更新 urgentCheckTask
        return loadUrgentRules(currentUserId, chatId);
      })
      .then(() => {
        urgentCheckTask.loadRules();
      })
      .catch(() => {
        setIsLoading(false);
        toggleAddUrgentAlert({ force: false });
      }).finally(() => {
        setIsLoading(false);
        toggleAddUrgentAlert({ force: false });
      });
  });

  const isSaveButtonShown = useMemo(() => {
    if (error) return false;
    if (editingRuleId) {
      // 编辑模式：任意字段与初始值不同时才显示
      return rule !== initialRule
        || notification !== initialNotification
        || callAlert !== initialCallAlert
        || phoneNumber !== initialPhone;
    }
    // 新增模式：有内容才显示
    return Boolean(phoneNumber) || Boolean(rule);
  }, [
    error, editingRuleId,
    rule, initialRule,
    notification, initialNotification,
    callAlert, initialCallAlert,
    phoneNumber, initialPhone,
  ]);

  return (
    <div className="h-full overflow-hidden px-[18px] flex flex-col  pt-[1rem]">
      <TextArea
        value={rule}
        onChange={handleRuleChange}
        label="Alert Rule"
        noReplaceNewlines
        disabled={isLoading}
        error={error === ERROR_RULE_MISSING ? error : undefined}
      />
      <div className="rounded-md flex flex-col gap-[16px] p-[16px] bg-[#EFF6FF] border border-[#BEDBFF] mb-[24px]">
        <div className="flex items-center gap-[12px]">
          <ExclamationCircleIcon size={20} className="flex-shrink-0 text-[#155DFC]" />
          <h3 className="text-[16px] text-[#1C398E]">Example Rules</h3>
        </div>
        <div className="flex flex-col gap-[12px]">
          <div className="text-[14px] flex gap-[8px]">
            <img src={MessageIconPath} alt="message" className="w-[16px] h-[16px] mt-[4px]" />
            <div className="flex flex-col">
              <span className="text-[14px] text-[var(--color-text)]">Keyword："Bitcoin", "ETH", "urgent"</span>
              <span className="text-[12px] text-[var(--color-text-secondary)]">
                Get alerts when specific keywords appear in messages
              </span>
            </div>
          </div>
          <div className="text-[14px] flex gap-[8px]">
            <img src={MessageIconPath} alt="message" className="w-[16px] h-[16px] mt-[4px]" />
            <div className="flex flex-col">
              <span className="text-[14px] text-[var(--color-text)]">Important announcements</span>
              <span className="text-[12px] text-[var(--color-text-secondary)]">
                AI understands context and intent beyond exact keywords
              </span>
            </div>
          </div>
          <div className="text-[14px] flex gap-[8px]">
            <img src={MessageIconPath} alt="message" className="w-[16px] h-[16px] mt-[4px]" />
            <div className="flex flex-col">
              <span className="text-[14px] text-[var(--color-text)]">Price drops or market changes</span>
              <span className="text-[12px] text-[var(--color-text-secondary)]">
                Monitor market updates with semantic understanding
              </span>
            </div>
          </div>
        </div>
      </div>
      <div className="flex flex-col gap-[8px]">
        <div className="flex items-center p-[16px] bg-[var(--color-chat-hover)] rounded-[16px]">
          <span className="text-[14px] flex-1 overflow-hidden text-ellipsis mr-[20px] whitespace-nowrap">TelyAI Notification</span>
          <Switcher
            label=""
            checked={notification}
            onChange={handleNotificationChange}
            noAnimation
          />
        </div>
        <div className="flex items-center p-[16px] bg-[var(--color-chat-hover)] rounded-[16px]">
          <span className="text-[14px] flex-1 overflow-hidden text-ellipsis mr-[20px] whitespace-nowrap">Call Alert</span>
          <Switcher
            label=""
            checked={callAlert}
            onChange={handleCallAlertChange}
            noAnimation
          />
        </div>
        <div className="mt-[12px]">
          <div className="text-[12px] text-[var(--color-text-secondary)]">
            After the phone number is modified, the phone numbers for other topics will also be changed simultaneously.
          </div>
          <InputText
            label="Your Phone Number"
            className="mt-[1.125rem]"
            value={phoneNumber}
            inputMode="tel"
            onChange={handlePhoneNumberChange}
            error={error === ERROR_PHONE_MISSING ? error : undefined}
          />
          <div className="text-[12px] text-[var(--color-text-secondary)]">
            Once enabled, these types of messages will trigger a phone alert.
          </div>
        </div>
      </div>
      <FloatingActionButton
        isShown={isSaveButtonShown}
        onClick={handleSave}
        disabled={isLoading}
      >
        {isLoading ? (
          <Spinner color="white" />
        ) : (
          <Icon name="check" />
        )}
      </FloatingActionButton>
    </div>
  );
};

export default memo(withGlobal<OwnProps>(
  (global): StateProps => {
    const { currentUserId } = global;
    const tabState = selectTabState(global);
    return {
      currentUserId,
      editingRuleId: tabState.editingUrgentRuleId,
    };
  },
)(AddUrgentAlert));
