import React, { memo, useCallback } from '@teact';
import { getActions, withGlobal } from '../../../../global';

import type { UrgentRule } from './types';

import { urgentCheckTask } from '../../ai-task/urgent-check-task';
import { useUrgentRules } from '../../hook/use-urgent-rules';

import Icon from '../../../common/icons/Icon';
import Button from '../../../ui/Button';
import DropdownMenu from '../../../ui/DropdownMenu';
import MenuItem from '../../../ui/MenuItem';
import Spinner from '../../../ui/Spinner';
import Switcher from '../../../ui/Switcher';
import { ExclamationCircleIcon } from './ExclamationCircleIcon';

interface StateProps {
  currentUserId?: string;
  chatId?: string;
}

export const UrgentAlert = ({ chatId, currentUserId }: StateProps) => {
  const { toggleAddUrgentAlert } = getActions();
  const { rules, isLoading, updateRule, deleteRule } = useUrgentRules({
    chatId,
    currentUserId,
    onRulesChanged: () => urgentCheckTask.loadRules(),
  });

  const handleEdit = useCallback((item: UrgentRule) => {
    toggleAddUrgentAlert({ editingRuleId: item.id });
  }, [toggleAddUrgentAlert]);

  return (
    <div className="h-full overflow-hidden px-[18px] flex flex-col pt-[1rem]">
      <div className="bg-[#7D40FF1A] rounded-md flex gap-[12px] p-[16px]">
        <ExclamationCircleIcon size={20} className="flex-shrink-0" />
        <div>
          <h3 className="text-[16px]">How AI Alerts Work</h3>
          <p className="text-[14px]">
            Set <b>keywords</b> to get instant alerts when mentioned. Or use <b>AI semantic monitoring</b> to detect messages matching your intent, even without exact keywords.
          </p>
        </div>
      </div>
      <div className="flex justify-between items-center mb-[12px] mt-[24px]">
        <span>Alert Rules</span>
        <Button
          noForcedUpperCase
          size="smaller"
          className="text-[14px] !py-[8px] !px-[12px] w-auto"
          onClick={() => toggleAddUrgentAlert()}
        >
          <Icon name="add" />
          <span>Add Alert Rule</span>
        </Button>
      </div>
      {isLoading ? (
        <div className="flex justify-center py-[24px]">
          <Spinner />
        </div>
      ) : (
        <div className="flex flex-col gap-[12px]">
          {rules.map((item) => (
            <div className="flex items-center p-[16px] bg-[var(--color-chat-hover)] rounded-[16px]">
              <span className="text-[14px] flex-1 overflow-hidden text-ellipsis mr-[20px] whitespace-nowrap">
                {item.rule}
              </span>
              <Switcher
                label=""
                checked={item.is_open}
                onChange={() => updateRule(item, { is_open: !item.is_open })}
                noAnimation
              />
              <DropdownMenu
                positionX="right"
                positionY="bottom"
              >
                <MenuItem icon="edit" onClick={() => handleEdit(item)}>Edit Rule</MenuItem>
                <MenuItem icon="delete" destructive onClick={() => deleteRule(item)}>Delete Rule</MenuItem>
              </DropdownMenu>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default memo(withGlobal(
  (global): StateProps => {
    const { currentUserId } = global;
    return { currentUserId };
  },
)(UrgentAlert));
