import React from '@teact';
import type { FC } from '../../../lib/teact/teact';

import type { OwnProps } from './TelyAIMemory';

import { Bundles } from '../../../util/moduleLoader';

import useModuleLoader from '../../../hooks/useModuleLoader';

import Loading from '../../ui/Loading';

const TelyAIMemoryAsync: FC<OwnProps> = (props) => {
  const TelyAIMemory = useModuleLoader(Bundles.Extra, 'TelyAIMemory');

  return TelyAIMemory ? <TelyAIMemory {...props} /> : <Loading />;
};

export default TelyAIMemoryAsync;
