import React from '@teact';
import type { FC } from '../../lib/teact/teact';

import type { ElectronUpdateProgress } from '../../types/electron';

import buildClassName from '../../util/buildClassName';

import useOldLang from '../../hooks/useOldLang';

import Button from '../ui/Button';
import Modal from '../ui/Modal';

import './ElectronUpdateModal.scss';

type OwnProps = {
  isOpen: boolean;
  status: 'checking' | 'downloading' | 'downloaded' | 'no-update' | 'error';
  version?: string;
  message?: string;
  progress?: ElectronUpdateProgress;
  onClose: NoneToVoidFunction;
  onInstall: NoneToVoidFunction;
};

const ElectronUpdateModal: FC<OwnProps> = ({
  isOpen,
  status,
  version,
  message,
  progress,
  onClose,
  onInstall,
}) => {
  const lang = useOldLang();

  const title = status === 'error'
    ? 'Update Error'
    : status === 'no-update'
      ? 'Check for Updates'
      : 'App Update';

  const percent = progress?.percent || 0;

  return (
    <Modal
      className={buildClassName('ElectronUpdateModal', status)}
      isOpen={isOpen}
      hasCloseButton
      title={title}
      onClose={onClose}
    >
      <div className="electron-update-modal-content">
        {status === 'checking' && (
          <p>{lang('CheckingForUpdate') || 'Checking for updates...'}</p>
        )}

        {status === 'downloading' && (
          <>
            <p>{version ? `New version ${version} is downloading...` : 'Downloading update...'}</p>
            <div className="electron-update-progress">
              <div className="electron-update-progress__bar">
                <div className="electron-update-progress__value" style={`width: ${percent}%;`} />
              </div>
              <div className="electron-update-progress__meta">
                <span>{percent}%</span>
                <span>{progress?.transferred || 0} / {progress?.total || 0}</span>
              </div>
            </div>
          </>
        )}

        {status === 'downloaded' && (
          <p>{version ? `Version ${version} is ready to install.` : 'Update is ready to install.'}</p>
        )}

        {status === 'no-update' && (
          <p>Your app is already up to date.</p>
        )}

        {status === 'error' && (
          <p>{message || 'Failed to check for updates.'}</p>
        )}

        <div className="dialog-buttons mt-2">
          {status === 'downloaded' ? (
            <Button className="confirm-dialog-button" isText onClick={onInstall}>
              Update Now
            </Button>
          ) : undefined}
        </div>
      </div>
    </Modal>
  );
};

export default ElectronUpdateModal;
