import { create } from 'zustand';

import type { AgentSelectedMessage } from '../../agent/types';

interface RoomAIState {
  chatId: string | undefined;
  selectedMessages: AgentSelectedMessage[];
  setChatId: (id: string | undefined) => void;
  setSelectedMessages: (msgs: AgentSelectedMessage[]) => void;
}

export const useRoomAIStore = create<RoomAIState>((set) => ({
  chatId: undefined,
  selectedMessages: [],
  setChatId: (chatId) => set({ chatId }),
  setSelectedMessages: (selectedMessages) => set({ selectedMessages }),
}));
