/**
 * ReferencesButton 组件
 * 显示"参考来源"按钮，点击后显示引用详情
 */
import React from 'react';
import { memo, useMemo } from 'react';
import { getGlobal } from '../../../global';

import type { MessageReference, WebReference } from '../messages/types';

import { selectChat, selectUser } from '../../../global/selectors';
import buildClassName from '../../../util/buildClassName';
import { isUserId } from '../../../util/entities/ids';

import Avatar from '../component/Avatar';

import styles from './ReferencesButton.module.scss';

interface OwnProps {
  messageReferences: MessageReference[];
  webpageReferences: WebReference[];
  onClick: () => void;
  className?: string;
}

// 头像组件 - 参考 global-summary-message.tsx
const ChatAvatar = ({ chatId, size }: { chatId: string; size: number }) => {
  const global = getGlobal();
  if (!chatId) return null;

  let peer;
  if (isUserId(chatId)) {
    peer = selectUser(global, chatId);
  } else {
    peer = selectChat(global, chatId);
  }

  return (
    <Avatar
      className={buildClassName(styles.avatar, 'overlay-avatar')}
      size={size}
      peer={peer}
      clickOpenRoom={false}
      clickOpenAIAssiatant={false}
    />
  );
};

const ReferencesButton = ({
  messageReferences,
  webpageReferences,
  onClick,
  className,
}: OwnProps) => {
  const totalCount = messageReferences.length + webpageReferences.length;

  if (totalCount === 0) {
    return null;
  }

  // 合并所有引用，最多显示 3 个
  const displayItems = useMemo(() => {
    const items: Array<{ type: 'message' | 'web'; data: MessageReference | WebReference }> = [];

    // 添加消息引用
    messageReferences.forEach((msg) => {
      if (items.length < 3) {
        items.push({ type: 'message', data: msg });
      }
    });

    // 添加网页引用
    webpageReferences.forEach((web) => {
      if (items.length < 3) {
        items.push({ type: 'web', data: web });
      }
    });

    return items;
  }, [messageReferences, webpageReferences]);

  const remainingCount = totalCount - displayItems.length;

  return (
    <div
      className={buildClassName(styles.root, 'flex items-center ml-auto', className)}
      onClick={onClick}
    >
      {/* 显示引用的头像/图标 */}
      <div className={styles.avatars}>
        {displayItems.map((item, index) => {
          if (item.type === 'message') {
            const msg = item.data as MessageReference;
            // 使用 senderId 或 chatId 来获取头像
            const avatarId = msg.senderId || msg.chatId;
            return (
              <ChatAvatar
                key={`msg-${msg.messageId}-${index}`}
                chatId={avatarId}
                size={24}
              />
            );
          } else {
            const web = item.data as WebReference;
            return (
              <div
                key={`web-${web.url}-${index}`}
                className={buildClassName(styles.avatar, styles.webAvatar)}
                title={web.title || web.url}
              >
                {web.favicon ? (
                  <img
                    src={web.favicon}
                    alt=""
                    className={styles.favicon}
                    onError={(e) => {
                      // 如果图标加载失败，显示默认图标
                      e.currentTarget.style.display = 'none';
                      const parent = e.currentTarget.parentElement;
                      if (parent) {
                        parent.textContent = '🌐';
                      }
                    }}
                  />
                ) : (
                  <span className={styles.webIcon}>🌐</span>
                )}
              </div>
            );
          }
        })}
        {remainingCount > 0 && (
          <div className={buildClassName(styles.avatar, styles.moreAvatar)}>
            +
            {remainingCount}
          </div>
        )}
      </div>

      {/* 文本 */}
      <span className={styles.text}>Source</span>
    </div>
  );
};

export default memo(ReferencesButton);
