import React from '@teact';
import type { FC } from '../../lib/teact/teact';

import type { ElectronUpdateProgress } from '../../types/electron';

import buildClassName from '../../util/buildClassName';

import Button from '../ui/Button';

import './ElectronUpdateFloatingButton.scss';

type OwnProps = {
  progress?: ElectronUpdateProgress;
  onClick: NoneToVoidFunction;
};

const ElectronUpdateFloatingButton: FC<OwnProps> = ({ progress, onClick }) => {
  const percent = Math.round(progress?.percent || 0);

  return (
    <Button
      type="button"
      className={buildClassName('ElectronUpdateFloatingButton')}
      onClick={onClick}
    >
      <span className="ElectronUpdateFloatingButton__progress">{percent}%</span>
    </Button>
  );
};

export default ElectronUpdateFloatingButton;
